cd /tmp/sv-1a4ae7a36b1c42bc82dcea7c6bba2835/symbols

# Let's find the nearest dynamic symbol for each address
# Sort exported symbols by address and find nearest match
llvm-nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | sort | awk '
BEGIN {
  targets[1] = "0x222098"
  targets[2] = "0x222234"
  targets[3] = "0x19bac0"
  targets[4] = "0x19bc14"
  ntargets = 4
}
{
  addr = strtonum("0x" $1)
  name = $3
  for (i = 1; i <= ntargets; i++) {
    taddr = strtonum(targets[i])
    if (addr <= taddr) {
      prev_name[i] = name
      prev_addr[i] = $1
    }
  }
}
END {
  for (i = 1; i <= ntargets; i++) {
    printf "PC %s -> %s+0x%x (%s)\n", targets[i], prev_name[i], strtonum(targets[i]) - strtonum("0x" prev_addr[i]), prev_addr[i]
  }
}
'

